def _env_bool(name: str, default: bool = False) -> bool:
    value = os.getenv(name)
    if value is None:
        return default
    return value.strip().lower() in {"1", "true", "yes", "on"}


def _parse_startup_nodes(raw: str):
    nodes = []
    for item in raw.split(","):
        item = item.strip()
        if not item:
            continue
        if ":" not in item:
            raise ValueError(f"Invalid REDIS_CLUSTER_NODES entry: {item}")
        host, port = item.rsplit(":", 1)
        nodes.append({"host": host.strip(), "port": int(port.strip())})
    if not nodes:
        raise ValueError("No valid REDIS_CLUSTER_NODES provided")
    return nodes


class RedisCacheService:
    def __init__(self):
        startup_nodes = _parse_startup_nodes(
            os.getenv("REDIS_CLUSTER_NODES", "127.0.0.1:6379")
        )
